## 思路

首先我们知道这道题暴力枚举肯定是不行的。因为 BST 的建树最坏情况为 $O(n)$。总时间复杂度 $O(n^2)$。非常不优秀。

所以我们尝试着思考 BST 的性质。我们发现一个新来的数会出现在有且仅有的两个地方。然后我们发现它会在**比它小的数中最大的数的右子树**与**比他大的数中最小的数的左子树**。而且同一时刻，有且仅有一个数的左右子树空闲。然后思路就可以顺而推出。

记录一个右子树是否为空闲的 bool 数组。然后对其进行判断。然后用一些方法去寻找这两个数。然后判断。如果只要有一个合法或不合法。另一个就不用判断了。

向大家推荐一个好方法曰 set。

[详细内容](https://blog.csdn.net/yas12345678/article/details/52601454)

## Code

```cpp
#include <iostream>
#include <set>
using namespace std;
#define int long long
bool has_right[300001];
int cnt[300001];
set<int>a;
void read(int &x)
{
	x = 0;
	char v = getchar();  
	while(v < '0' || v > '9')
	v = getchar();
	while(v >= '0' && v <= '9')
	{
		x = (x << 3) + (x << 1) + (v & 15);
		v = getchar();
	}
}
void write(int x)
{
	if(x < 10)
	{
		putchar(x | 48);
		return ;
	}
	write(x / 10);
	putchar(x % 10 | 48);
}
int x[300001];
signed main()
{
	int n;
	cin >> n;
	int ans = 0;
	for(int i = 1;i <= n;++ i)
	read(x[i]);
	for(int i = 1;i <= n;++ i)
	{
		if(i == 1)
		{
			a.insert(x[i]);
			write(ans) , putchar('\n');
			continue;
		}
		auto it = a.lower_bound(x[i]);
		auto its = a.upper_bound(x[i]);
		if(it != a.begin())
		{
			-- it;
			if(!has_right[*it])
			{
				has_right[*it] = true;
				cnt[x[i]] = cnt[*it] + 1;
				a.insert(x[i]);
				ans += cnt[x[i]];
			}
			else
			{
				cnt[x[i]] = cnt[*its] + 1;
				a.insert(x[i]);
				ans += cnt[x[i]];
			}
		}
		else
		{
			cnt[x[i]] = cnt[*its] + 1;
			a.insert(x[i]);
			ans += cnt[x[i]];
		}
		write(ans);
		putchar('\n');
	}
	return 0;
}
```
