	for(int i=1;i<=n;i++)lft[i]=i-1,rgt[i]=i+1;
	rgt[n]=0;dep[0]=-1;
	for(int i=n;i>=1;i--){
		ln[a[i]]=lft[a[i]];rn[a[i]]=rgt[a[i]];
		rgt[lft[a[i]]]=rgt[a[i]];
		lft[rgt[a[i]]]=lft[a[i]];
	} 
	for(int i=1;i<=n;i++){
		dep[a[i]]=1+max(dep[ln[a[i]]],dep[rn[a[i]]]);
		ans+=dep[a[i]];
		printf("%lld\n",ans);
	}
}
